import { useState } from "react";

export default function CrystalBall() {
  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [loading, setLoading] = useState(false);

  function askCrystalBall() {
    if (!question.trim() || loading) return;

    setLoading(true);
    setAnswer("");

    setTimeout(() => {
      const prediction = Math.random() < 0.5 ? "✅ Yes" : "❌ No";
      setAnswer(prediction);
      setLoading(false);
    }, 2000);
  }

  return (
    <div
      style={{
        maxWidth: 400,
        margin: "40px auto",
        textAlign: "center",
        fontFamily: "sans-serif",
      }}
    >
      <h1>🔮 Crystal Ball</h1>

      <input
        type="text"
        placeholder="Ask a yes/no question..."
        value={question}
        onChange={(e) => setQuestion(e.target.value)}
        style={{
          width: "100%",
          padding: "10px",
          fontSize: "16px",
          marginBottom: "10px",
        }}
      />

      <button
        onClick={askCrystalBall}
        disabled={loading || !question.trim()}
        style={{
          padding: "10px 20px",
          fontSize: "16px",
          cursor: "pointer",
        }}
      >
        Ask
      </button>

      <div
        style={{
          marginTop: "30px",
          minHeight: "80px",
          fontSize: "28px",
        }}
      >
        {loading ? (
          <>
            <div
              style={{
                width: 32,
                height: 32,
                margin: "0 auto 12px",
                border: "4px solid #ddd",
                borderTop: "4px solid #555",
                borderRadius: "50%",
                animation: "spin 1s linear infinite",
              }}
            />
            <p>🔮 Consulting the spirits...</p>
          </>
        ) : (
          answer && <h2>{answer}</h2>
        )}
      </div>

      <style>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}
